@Configuration
@EnableRetry
public class DataSourceConfig {
    @Bean
    @Retryable(
        value = {SQLException.class},
        maxAttempts = 5,
        backoff = @Backoff(delay = 2000, multiplier = 2))
    public DataSource dataSource() throws SQLException {
        HikariConfig config = new HikariConfig();
        config.setJdbcUrl(dbUrl);
        HikariDataSource ds = new HikariDataSource(config);
        ds.getConnection().isValid(1); // test connection
        return ds;
    }

    @Recover
    public DataSource recover(SQLException ex) {
        log.error("DB not available after retries", ex);
        throw new ApplicationStartupException("DB unavailable", ex);
    }
}

