// Efficient interceptor — minimal overhead
@Component
public class RequestTimingInterceptor implements HandlerInterceptor {
    private static final String START_TIME = "__startTime";

    @Override
    public boolean preHandle(HttpServletRequest req,
            HttpServletResponse res, Object handler) {
        req.setAttribute(START_TIME, System.nanoTime());
        return true; // must return true to continue chain
    }

    @Override
    public void afterCompletion(HttpServletRequest req,
            HttpServletResponse res, Object handler, Exception ex) {
        long start = (long) req.getAttribute(START_TIME);
        long elapsed = (System.nanoTime() - start) / 1_000_000;
        // No I/O here — just metrics counter increment
        metricsRegistry.timer("http.request").record(elapsed, MILLISECONDS);
    }
}

// Register with path restriction
@Configuration
public class WebConfig implements WebMvcConfigurer {
    @Override
    public void addInterceptors(InterceptorRegistry registry) {
        registry.addInterceptor(requestTimingInterceptor)
            .addPathPatterns("/api/**")
            .excludePathPatterns("/actuator/**");
        // Order matters: auth before logging
        registry.addInterceptor(authInterceptor).order(1);
        registry.addInterceptor(loggingInterceptor).order(2);
    }
}

