// Multi-layer fault tolerance
@Service
public class PaymentGatewayClient {

    private final WebClient webClient;

    public PaymentGatewayClient(WebClient.Builder builder) {
        this.webClient = builder
            .baseUrl("https://payment-gateway.com")
            .build();
    }

    @CircuitBreaker(name = "gateway", fallbackMethod = "fallback")
    @Retry(name = "gateway")
    @Bulkhead(name = "gateway", type = Bulkhead.Type.THREADPOOL)
    public CompletableFuture<PaymentResult> charge(
            PaymentRequest request) {
        return webClient.post().uri("/charge")
            .bodyValue(request)
            .retrieve()
            .bodyToMono(PaymentResult.class)
            .timeout(Duration.ofSeconds(5))
            .toFuture();
    }

    public CompletableFuture<PaymentResult> fallback(
            PaymentRequest request, Throwable t) {
        // Queue for async processing
        pendingPaymentsQueue.add(request);
        return CompletableFuture.completedFuture(
            PaymentResult.pending(request.getOrderId()));
    }
}

