// Runnable — no return value, no checked exception
Runnable task = () -> {
    System.out.println("Processing in thread: " +
        Thread.currentThread().getName());
    // Cannot throw checked exception
};

// Callable — returns value, can throw checked exception
Callable<Integer> computation = () -> {
    Thread.sleep(1000); // checked exception — OK in Callable
    return 42;
};

ExecutorService pool = Executors.newFixedThreadPool(4);

// Submit Runnable
Future<?> rFuture = pool.submit(task);
rFuture.get(); // Always null

// Submit Callable
Future<Integer> cFuture = pool.submit(computation);
try {
    Integer result = cFuture.get(5, TimeUnit.SECONDS);
    System.out.println("Result: " + result); // 42
} catch (ExecutionException ex) {
    // Wraps exception thrown by call()
    log.error("Task failed", ex.getCause());
} catch (TimeoutException ex) {
    cFuture.cancel(true);
}

// Unchecked exception in Runnable — SILENTLY SWALLOWED
Future<?> bad = pool.submit(() -> {
    throw new RuntimeException("This is lost!");
});
// No exception visible unless you call:
bad.get(); // Throws ExecutionException wrapping RuntimeException

// Modern approach — CompletableFuture
CompletableFuture.supplyAsync(() -> expensiveCalculation())
    .thenApply(result -> result * 2)
    .exceptionally(ex -> 0)
    .thenAccept(System.out::println);

// WITHOUT happens-before — BROKEN
class BrokenVisibility {
    private boolean ready = false;
    private int data = 0;

    // Thread 1 writes
    public void writer() {
        data = 42;
        ready = true;  // May be reordered BEFORE data=42!
    }

    // Thread 2 reads
    public void reader() {
        while (!ready) {} // May spin forever OR see ready=true, data=0
        System.out.println(data); // May print 0!
    }
}

// WITH volatile — establishes happens-before
class CorrectVisibility {
    private volatile boolean ready = false;
    private int data = 0;

    public void writer() {
        data = 42;      // HB: happens before volatile write
        ready = true;  // Volatile write — establishes HB
    }

    public void reader() {
        while (!ready) {} // Volatile read — sees everything before write
        System.out.println(data); // GUARANTEED to print 42
    }
}

