public void publishOutboxEvents() {
    List<OutboxEvent> events = outboxRepo.findUnpublished();
    events.forEach(event -> {
        kafkaTemplate.send(event.getTopic(), event.getAggregateId(),
            event.getPayload());
        event.setPublished(true);
        outboxRepo.save(event);
    });
}

