@RestController
@RequestMapping("/api/v1/orders")
public class OrderController {

    // GET — retrieve resource
    @GetMapping("/{id}")
    public ResponseEntity<OrderDto> getOrder(@PathVariable Long id) {
        return ResponseEntity.ok(orderService.findById(id));
    }

    // GET — list with query params
    @GetMapping
    public Page<OrderDto> listOrders(
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "20") int size,
            @RequestParam(required = false) String status) {
        return orderService.findAll(status, PageRequest.of(page, size));
    }

    // POST — create resource
    @PostMapping
    public ResponseEntity<OrderDto> createOrder(
            @RequestBody @Valid CreateOrderRequest req) {
        OrderDto created = orderService.create(req);
        URI location = URI.create("/api/v1/orders/" + created.getId());
        return ResponseEntity.created(location).body(created);
    }

    // PUT — full update
    @PutMapping("/{id}")
    public OrderDto updateOrder(@PathVariable Long id,
            @RequestBody @Valid UpdateOrderRequest req) {
        return orderService.update(id, req);
    }

    // PATCH — partial update
    @PatchMapping("/{id}/status")
    public OrderDto updateStatus(@PathVariable Long id,
            @RequestParam String status) {
        return orderService.updateStatus(id, status);
    }

    // DELETE — remove resource
    @DeleteMapping("/{id}")
    @ResponseStatus(HttpStatus.NO_CONTENT)
    public void deleteOrder(@PathVariable Long id) {
        orderService.delete(id);
    }
}

