// Problem: insufficient capacity -> frequent resizing
Map<String, Data> map = new HashMap<>(); // starts at 16
// Resize chain: 16->32->64->... for millions of entries

// Fix: pre-size
int expected = 1_000_000;
Map<String, Data> map = new HashMap<>(expected * 4 / 3 + 1); // no resizing

// Verify hashCode quality
Map<Integer, Long> distribution = data.keySet().stream()
    .collect(Collectors.groupingBy(
        k -> Math.abs(k.hashCode()) % 16, Collectors.counting()));
// Ideal: ~equal counts per bucket. If one bucket >> others: bad hashCode

// BAD: ConcurrentModificationException
List<String> list = new ArrayList<>(Arrays.asList("a", "b", "c"));
for (String item : list) {
    if (item.equals("b")) list.remove(item); // throws CME!
}

// GOOD: Iterator.remove()
Iterator<String> iter = list.iterator();
while (iter.hasNext()) {
    if (iter.next().equals("b")) iter.remove();
}

// GOOD: removeIf (Java 8+)
list.removeIf(item -> item.equals("b"));

// GOOD: thread-safe iteration
List<String> safe = new CopyOnWriteArrayList<>(list);
for (String item : safe) { // iterates snapshot
    if (item.equals("b")) safe.remove(item);
}

