@SpringBootApplication
public class App {
    public static void main(String[] args) {
        // SpringApplication.run() orchestrates all phases
        SpringApplication app = new SpringApplication(App.class);

        // Add listener for each phase
        app.addListeners(
            (ApplicationStartingEvent e) ->
                System.out.println("1. Starting"),
            (ApplicationEnvironmentPreparedEvent e) ->
                System.out.println("2. Environment ready"),
            (ApplicationContextInitializedEvent e) ->
                System.out.println("3. Context initialized"),
            (ApplicationPreparedEvent e) ->
                System.out.println("4. Context prepared"),
            (ContextRefreshedEvent e) ->
                System.out.println("5. Context refreshed"),
            (ApplicationStartedEvent e) ->
                System.out.println("6. Application started"),
            (ApplicationReadyEvent e) ->
                System.out.println("7. Application READY")
        );
        app.run(args);
    }
}

