// @Controller — methods return view names OR @ResponseBody
@Controller
public class HybridController {
    // Returns view template
    @GetMapping("/page")
    public String page(Model model) {
        model.addAttribute("data", "value");
        return "my-template"; // ViewResolver resolves to templates/my-template.html
