// @RestController — ALL methods return body (no view resolution)
@RestController
public class ApiController {
    @GetMapping("/data")
    public DataDto data() {
        return new DataDto("value"); // Always JSON (default)
    }

    // Content negotiation via Accept header
    @GetMapping(value = "/data",
        produces = {MediaType.APPLICATION_JSON_VALUE,
                    MediaType.APPLICATION_XML_VALUE})
    public DataDto dataWithNegotiation() {
        return new DataDto("value");
        // application/json -> Jackson JSON
        // application/xml  -> Jackson XML or JAXB
    }
}

