@Component
public class ManualInjectionExample {
    // Spring injects this:
    @Autowired
    private PaymentService paymentService;

    // Equivalent programmatic lookup:
    @Autowired
    ApplicationContext ctx;

    public void programmaticLookup() {
        // Lookup by type
        PaymentService ps = ctx.getBean(PaymentService.class);
        // Lookup by name and type
        PaymentService ps2 = ctx.getBean(
            "paymentService", PaymentService.class);
    }
}

